import{_ as a,o as r,c as t,ae as i}from"./chunks/framework.B6gjLfeO.js";const p=JSON.parse('{"title":"Billing Overview","description":"","frontmatter":{"title":"Billing Overview","slug":"billing-overview"},"headers":[],"relativePath":"account-hub/billing-overview.md","filePath":"account-hub/billing-overview.md"}'),n={name:"account-hub/billing-overview.md"};function o(l,e,s,c,u,d){return r(),t("div",null,[...e[0]||(e[0]=[i('<h3 id="trials" tabindex="-1">Trials <a class="header-anchor" href="#trials" aria-label="Permalink to &quot;Trials&quot;">​</a></h3><p>You&#39;re welcome to sign up for Branch on a <strong>30-day</strong> trial. This trial allows you to use our <strong>self-serve</strong> offerings at no cost. You&#39;ll be asked to add a credit card to your account at sign-up.</p><p>Trials begin immediately upon sign-up, and you won&#39;t be charged for any usage during this trial period. After the 30-day trial, you&#39;ll be asked to select a package, and you&#39;ll start to be charged for <a href="./usage.html#volume-credits">volume credit usage</a>.</p><h2 id="billing-management" tabindex="-1">Billing management <a class="header-anchor" href="#billing-management" aria-label="Permalink to &quot;Billing management&quot;">​</a></h2><p>View invoices in the <strong>Billing</strong> <a href="https://dashboard.branch.io/account-settings/billing" target="_blank" rel="noreferrer">tab</a> of the Settings page in Branch.</p><p>If you have any questions regarding your contract or would like to make changes, reach out to your account manager or <a href="https://www.branch.io/contact-sales/" target="_blank" rel="noreferrer">contact sales</a>.</p><p>For more information on managing your billing details, view our dedicated <a href="./manage-billing.html">Manage Billing guide</a>.</p><h3 id="billing-cadence" tabindex="-1">Billing cadence <a class="header-anchor" href="#billing-cadence" aria-label="Permalink to &quot;Billing cadence&quot;">​</a></h3><p>Branch&#39;s service period runs from the 1st of the month to the last day of the month. Your Branch billing cycle is recurrent and occurs monthly on the 1st of every month. Branch bills in periods; as such, Branch will send your invoice at the end of the service period, rather than upfront (in advance).</p><p>If you sign up partway through the month, your first invoice will be prorated.</p><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><details><summary>What happens if I sign up partway through the month?</summary><p>All partial billing periods will be prorated and paid usage won&#39;t begin until your trial is over. If you sign up for a premium product partway through the month, your first invoice will be prorated.</p><p>For example, if you sign up on May 25th, your trial will start on May 25th and will run for 14 days, until June 7th. Your charges and usage will accrue from June 8th to June 30th, and your first invoice will be issued during the first week of July.</p></details><details><summary>What happens if my credit card is not accepted (Error 322)?</summary><p>If the system provides an Error 322 when entering your credit card, follow these troubleshooting steps:</p><ol><li>Verify the billing address matches the billing address on your credit card statement</li><li>Verify that there aren’t too many sales/authorizations on your card in a short period of time</li><li>For international customers, verify your credit card has permission to accept US charges</li><li>Verify your credit card is not a prepaid card</li></ol><p>If you continue to experience issues, please contact your financial institution for further assistance. If there’s any action and/or transaction Branch can help with, contact our support team at <a href="mailto:billing@branch.io" target="_blank" rel="noreferrer">billing@branch.io</a>.</p></details><details><summary>When will I be billed?</summary><p>For online subscriptions (e.g. customer signs up to Branch’s premium products directly from the website), you will be billed during the first week of the calendar month. Branch bills in arrears. As such, Branch will send your invoice at the end of the service period, rather than upfront (in advance).</p></details><details><summary>What payment methods are accepted?</summary><p>For online subscriptions, we only accept credit cards. Please ensure your credit card meets the following criteria:</p><ul><li>Credit card must be a revolving account with a line of credit</li><li>The billing address entered matches the billing address in your credit card statement</li><li>For international customers, make sure the credit card accepts foreign transactions</li></ul><p>Once your payment and billing information has been entered, no further action is required to pay off your monthly invoice.</p></details>',15)])])}const g=a(n,[["render",o]]);export{p as __pageData,g as default};
